let keywords;
try { keywords = JSON.parse($json.Body || $json.body || '[]'); } catch(e) { keywords = []; }
if (!Array.isArray(keywords) || keywords.length === 0) {
  keywords = ['NHL playoff analytics','expected goals hockey explained','Corsi stat guide','hockey analytics 2026','advanced defensive metrics NHL'];
}
const pick = keywords[Math.floor(Math.random() * keywords.length)];
const keyword = typeof pick === 'string' ? pick : pick.keyword;
return [{ json: { keyword } }];

// Extract the generated content from Groq response
const response = $input.item.json;
const rawContent = response.choices[0].message.content;

// Extract SEO title and meta description from new format
const seoTitleMatch = rawContent.match(/SEO_TITLE:\s*(.+?)\n/);
const metaDescMatch = rawContent.match(/META_DESC:\s*(.+?)\n/);

// Remove the SEO_TITLE and META_DESC lines from content
let content = rawContent
  .replace(/SEO_TITLE:\s*.+?\n/, '')
  .replace(/META_DESC:\s*.+?\n/, '')
  .trim();

const seoTitle = seoTitleMatch ? seoTitleMatch[1].trim() : $('Pick Random Keyword').item.json.keyword;
const metaDescription = metaDescMatch ? metaDescMatch[1].trim() : '';

// Extract H1 title from content
const h1Match = content.match(/^#\s*(.+?)\n/);
const title = h1Match ? h1Match[1].trim() : seoTitle;

// Remove the H1 from content since PostHeader will render the title
content = content.replace(/^#\s*.+?\n/, '').trim();

// Create slug from keyword
const slug = $('Pick Random Keyword').item.json.keyword
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '');

// Get current date and time for unique filename
const now = new Date();
const date = now.toISOString().split('T')[0];
const timestamp = now.getTime().toString().slice(-6);

return {
  content: content,
  title: title,
  seoTitle: seoTitle,
  metaDescription: metaDescription,
  slug: slug,
  keyword: $('Pick Random Keyword').item.json.keyword,
  filename: `${date}-${slug}-${timestamp}.md`
};

// Generate approval webhook URL and Minio preview URL
// Get metadata from the Format node (before upload)
const slug = $('Format & Extract Metadata').item.json.slug;
const keyword = $('Format & Extract Metadata').item.json.keyword;
const title = $('Format & Extract Metadata').item.json.title;
const filename = $('Format & Extract Metadata').item.json.filename;

// Your Minio configuration
const minioEndpoint = 'https://minio-api.thehockeyanalytics.com';
const minioBucket = 'seo-drafts';
const previewUrl = `${minioEndpoint}/${minioBucket}/${filename}`;

const webhookUrl = 'https://n8n.theunnamedroads.com/webhook/approve-seo-article';

// Pass through all metadata for Telegram notification
return {
  slug: slug,
  keyword: keyword,
  title: title,
  filename: filename,
  previewUrl: previewUrl,
  approveUrl: `${webhookUrl}?action=approve&filename=${encodeURIComponent(filename)}&slug=${encodeURIComponent(slug)}&keyword=${encodeURIComponent(keyword)}`,
  rejectUrl: `${webhookUrl}?action=reject&filename=${encodeURIComponent(filename)}`
};

const content = $('Format & Extract Metadata').item.json.content || '';
const title = $('Format & Extract Metadata').item.json.title || '';
const meta = $('Format & Extract Metadata').item.json.metaDescription || '';
const slug = $('Format & Extract Metadata').item.json.slug || '';

let score = 0;
const checks = {};

// Length: 700+ words = 2pts, 400+ = 1pt
const wordCount = content.split(/\s+/).length;
checks.word_count = wordCount;
score += wordCount >= 700 ? 2 : wordCount >= 400 ? 1 : 0;

// Has H2 headers
const h2Count = (content.match(/^## /gm) || []).length;
checks.h2_count = h2Count;
score += h2Count >= 3 ? 2 : h2Count >= 1 ? 1 : 0;

// Has intro (first para > 100 chars)
const firstPara = content.split('\n\n')[0] || '';
checks.has_intro = firstPara.length > 100;
score += checks.has_intro ? 1 : 0;

// Has conclusion/summary
const hasConclusion = /conclusion|summary|takeaway|key point/i.test(content);
checks.has_conclusion = hasConclusion;
score += hasConclusion ? 1 : 0;

// Title has keyword
const kw = $('Pick Random Keyword').item.json.keyword || '';
const titleHasKw = title.toLowerCase().includes(kw.split('-')[0]);
checks.title_has_keyword = titleHasKw;
score += titleHasKw ? 1 : 0;

// Meta description exists and is good length
checks.meta_length = meta.length;
score += meta.length >= 100 && meta.length <= 160 ? 1 : meta.length > 50 ? 0.5 : 0;

// Slug is clean
checks.slug_clean = /^[a-z0-9-]+$/.test(slug);
score += checks.slug_clean ? 1 : 0;

// No error markers
const hasError = /\[error\]|undefined|null/i.test(content);
checks.no_errors = !hasError;
score += !hasError ? 1 : 0;

const finalScore = Math.min(10, Math.round(score * 10 / 10));
const input = $input.item.json;
return { ...input, quality_score: finalScore, quality_checks: checks };

const meta = $('Format & Extract Metadata').item.json;
const q = $('Quality Score').item.json;
const text = '🤖 <b>Auto-publicerad – thehockeyanalytics.com</b>\n\n' +
  '<b>Titel:</b> ' + meta.title + '\n' +
  '<b>Keyword:</b> ' + meta.keyword + '\n' +
  '<b>Kvalitet:</b> ' + q.quality_score + '/10\n' +
  '🔗 https://www.thehockeyanalytics.com/posts/' + meta.slug;
return { json: { telegramText: text } };

function parseRSS(xml, maxItems) {
  if (!xml || typeof xml !== 'string') return [];
  const items = [];
  const matches = xml.match(/<item[\s>][\s\S]*?<\/item>/gi) ||
                  xml.match(/<entry[\s>][\s\S]*?<\/entry>/gi) || [];
  for (const item of matches.slice(0, maxItems)) {
    const titleMatch = item.match(/<title[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i);
    const title = (titleMatch?.[1] || '').replace(/<[^>]+>/g, '').trim();
    if (title.length > 10) items.push(title);
  }
  return items;
}

